@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix ns1: <http://spdx.org/rdf/terms#> .
@prefix ns2: <https://cdif.org/0.1/> .
@prefix ns3: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a ns3:PhysicalDataSet,
                        ns3:StructuredDataSet,
                        schema1:DataDownload ;
                    schema1:contentUrl "https://example.org/data/gom-temp-cube-2025.nc" ;
                    schema1:encodingFormat "application/x-netcdf" ;
                    schema1:name "Gulf of Maine temperature cube (NetCDF-4)" ;
                    ns1:checksum [ a ns1:Checksum ;
                            ns1:algorithm "SHA256" ;
                            ns1:checksumValue "9f3c1a0b4e8d2f1e7a6c5b4d3a2918f0e1d2c3b4a5968778a9b0c1d2e3f40516" ] ;
                    ns2:fileSize 1.846e+02 ;
                    ns2:fileSizeUofM "MB" ;
                    ns2:hasPhysicalMapping [ ns3:isRequired true ;
                            ns2:format "decimal" ;
                            ns2:formats_InstanceVariable <https://example.org/var-depth> ;
                            ns2:index 1 ;
                            ns2:locator "/depth" ;
                            ns2:physicalDataType "float32" ],
                        [ ns3:isRequired true ;
                            ns2:format "decimal" ;
                            ns2:formats_InstanceVariable <https://example.org/var-lon> ;
                            ns2:index 3 ;
                            ns2:locator "/lon" ;
                            ns2:physicalDataType "float32" ],
                        [ ns3:isRequired true ;
                            ns2:format "decimal" ;
                            ns2:formats_InstanceVariable <https://example.org/var-lat> ;
                            ns2:index 2 ;
                            ns2:locator "/lat" ;
                            ns2:physicalDataType "float32" ],
                        [ ns3:isRequired true ;
                            ns3:nullSequence "NaN" ;
                            ns2:format "decimal" ;
                            ns2:formats_InstanceVariable <https://example.org/var-temperature> ;
